import React, { useEffect, useState, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ActivityData, FoodHistoryItem } from '../types';
import { Flame, Footprints, Target, Bell, Utensils, X, Loader2, ChevronRight, Trophy, Zap, Play, Pause } from 'lucide-react';
import StreakWidget from './StreakWidget';
import StreakHistory from './StreakHistory';
import { supabase, updateUserTargets, fetchStreakCalendarData } from '../services/supabase';

interface DashboardProps {
  data: ActivityData;
  onUpdateGoals: (newGoals: Partial<ActivityData>) => void;
  isTracking: boolean;
  onToggleTracking: () => Promise<void>;
  status?: 'Idle' | 'Active' | 'Walking';
  error?: string | null;
  isSupported?: boolean;
  adaptiveGoalsEnabled: boolean;
  onToggleAdaptiveGoals: (enabled: boolean) => void;
  foodHistory?: FoodHistoryItem[];
}

const MOTIVATIONAL_QUOTES = [
  "Excellence is a habit.", 
  "Beat your past self.", 
  "Pain is growth.", 
  "Stay disciplined.", 
  "Focus on metrics."
];

let hasShownQuote = false;

const ProgressRing: React.FC<{ 
  progress: number; 
  color: string; 
  icon: React.ReactNode;
  size?: number;
  strokeWidth?: number;
}> = ({ progress, color, icon, size = 100, strokeWidth = 8 }) => {
  const radius = (size / 2) - (strokeWidth * 1.5); 
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (Math.min(100, progress) / 100) * circumference;
  const center = size / 2;

  return (
    <div 
      className="relative flex items-center justify-center p-[10px]"
      style={{ width: size + 20, height: size + 20 }}
    >
      <svg 
        width={size} 
        height={size} 
        viewBox={`0 0 ${size} ${size}`} 
        className="-rotate-90 overflow-visible"
      >
        <circle 
          cx={center} 
          cy={center} 
          r={radius} 
          stroke="rgba(255,255,255,0.1)" 
          strokeWidth={strokeWidth} 
          fill="transparent" 
        />
        <motion.circle 
          cx={center} 
          cy={center} 
          r={radius} 
          stroke={color} 
          strokeWidth={strokeWidth} 
          fill="transparent" 
          strokeDasharray={circumference} 
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset: offset }}
          strokeLinecap="round"
          className="transition-all duration-1000 ease-out"
          style={{ filter: `drop-shadow(0 0 8px ${color}44)` }}
        />
      </svg>
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="text-white">
          {icon}
        </div>
      </div>
    </div>
  );
};

const DailyFuelDial: React.FC<{
  currentCalories: number;
  goalCalories: number;
  steps: number;
  isMet: boolean;
  isTracking: boolean;
  onToggleTracking: () => void;
}> = ({ currentCalories, goalCalories, steps, isMet, isTracking, onToggleTracking }) => {
  const progress = (currentCalories / goalCalories) * 100;

  return (
    <div className="flex flex-col items-center justify-center py-6">
      <ProgressRing 
        progress={progress} 
        color={isMet ? '#CEF245' : '#555'} 
        size={280} 
        strokeWidth={14}
        icon={
          <div className="flex flex-col items-center justify-center text-center -mt-4">
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-500 mb-2">Step Count</p>
            <motion.h2 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-6xl font-black text-white leading-none tracking-tighter"
            >
              {steps.toLocaleString()}
            </motion.h2>
            <div className="mt-4 flex flex-col items-center">
              <span className="text-[10px] font-black uppercase text-luxury-neon tracking-widest">
                {Math.floor(currentCalories)} / {goalCalories} KCAL
              </span>
            </div>
          </div>
        }
      />

      <motion.button
        whileTap={{ scale: 0.95 }}
        onClick={(e) => {
            e.stopPropagation();
            onToggleTracking();
        }}
        className={`mt-10 px-12 py-4 rounded-full flex items-center justify-center gap-3 transition-all duration-300 backdrop-blur-md ${
          isTracking
            ? 'bg-black/60 border border-red-500 text-red-500 shadow-[0_0_20px_rgba(239,68,68,0.4)] hover:bg-red-500/10'
            : 'bg-luxury-neon text-black border border-luxury-neon shadow-[0_0_30px_rgba(206,242,69,0.4)] hover:scale-105'
        }`}
      >
        {isTracking ? (
            <>
                <Pause size={20} fill="currentColor" />
                <span className="font-black uppercase tracking-widest text-xs">Pause</span>
            </>
        ) : (
            <>
                <Play size={20} fill="currentColor" />
                <span className="font-black uppercase tracking-widest text-xs">Resume</span>
            </>
        )}
      </motion.button>
    </div>
  );
};

const MetricCard: React.FC<{
  label: string;
  value: string | number;
  unit: string;
  icon: React.ReactNode;
  progress: number;
  color: string;
  delay: number;
}> = ({ label, value, unit, icon, progress, color, delay }) => (
  <motion.div 
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ delay }}
    className="glass-card flex flex-col items-center justify-center p-4 rounded-[2.5rem] h-auto border border-white/5"
  >
    <div className="relative mb-2">
      <ProgressRing 
        progress={progress} 
        color={color} 
        size={80} 
        strokeWidth={6} 
        icon={icon} 
      />
    </div>
    <div className="text-center">
      <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-1">{label}</p>
      <div className="flex items-baseline justify-center gap-1">
        <span className="text-2xl font-black text-white">{value}</span>
        <span className="text-[9px] font-black text-gray-600 uppercase tracking-widest">{unit}</span>
      </div>
    </div>
  </motion.div>
);

const Dashboard: React.FC<DashboardProps> = ({ data, onUpdateGoals, isTracking, onToggleTracking, foodHistory = [] }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [notification, setNotification] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const [userId, setUserId] = useState<string | null>(null);

  // New State for Streak Logic
  const [completedDates, setCompletedDates] = useState<string[]>([]);

  const [localCalorieGoal, setLocalCalorieGoal] = useState<number>(data.calorieGoal);
  const [localStepGoal, setLocalStepGoal] = useState<number>(data.stepGoal);
  const [localDistanceGoal, setLocalDistanceGoal] = useState<number>(data.distanceGoal);

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => { 
        if (data.user) {
            setUserId(data.user.id);
            fetchStreakCalendarData(data.user.id).then(res => {
                if (res) setCompletedDates(res.streakDates);
            });
        }
    });

    if (!hasShownQuote) {
       hasShownQuote = true; 
       const q = MOTIVATIONAL_QUOTES[Math.floor(Math.random() * MOTIVATIONAL_QUOTES.length)];
       const timer = setTimeout(() => setNotification(q), 2000);
       const hideTimer = setTimeout(() => setNotification(null), 7000);
       return () => { clearTimeout(timer); clearTimeout(hideTimer); };
    }
  }, []);

  // Sync state when props update
  useEffect(() => {
      setLocalCalorieGoal(data.calorieGoal);
      setLocalStepGoal(data.stepGoal);
      setLocalDistanceGoal(data.distanceGoal);
  }, [data.calorieGoal, data.stepGoal, data.distanceGoal]);

  // Optimistic Streak Update: If today is met, add to list immediately for display
  const displayDates = useMemo(() => {
     const today = new Date().toISOString().split('T')[0];
     const isTodayMet = data.steps >= data.stepGoal;
     if (isTodayMet && !completedDates.includes(today)) {
         return [...completedDates, today];
     }
     return completedDates;
  }, [completedDates, data.steps, data.stepGoal]);

  const totalFuel = foodHistory.reduce((acc, item) => acc + (item.analysis?.macros?.calories || 0), 0);
  const isTargetMet = totalFuel >= data.calorieGoal;

  const handleApplyProtocols = async () => {
    if (!userId) return;
    setIsSaving(true);
    try {
      await updateUserTargets(userId, { 
          calories: localCalorieGoal, 
          steps: localStepGoal,
          distance: localDistanceGoal 
      });
      onUpdateGoals({ 
          calorieGoal: localCalorieGoal, 
          stepGoal: localStepGoal,
          distanceGoal: localDistanceGoal
      });
      setIsEditing(false);
    } catch (e) {
      alert("Failed to sync targets.");
    } finally { setIsSaving(false); }
  };

  return (
    <div className="h-full w-full overflow-y-auto no-scrollbar overscroll-y-contain p-6 space-y-8 pb-32">
      <AnimatePresence>
        {notification && (
          <motion.div initial={{ y: -100, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ opacity: 0, y: -20 }} className="fixed top-12 left-8 right-8 z-[100] glass-card p-4 rounded-2xl flex items-center gap-4 shadow-2xl">
             <Bell size={18} className="text-luxury-neon animate-pulse" />
             <p className="text-white font-medium text-xs italic">"{notification}"</p>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex justify-between items-center mt-4">
        <div>
          <p className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.3em] mb-1">Ecosystem Control</p>
          <h1 className="text-4xl font-black text-white tracking-tighter">Dashboard</h1>
        </div>
        <button 
          onClick={() => setIsEditing(true)} 
          className="w-12 h-12 glass-card rounded-full flex items-center justify-center hover:bg-white/10 transition-colors"
        >
          <Target size={20} className="text-luxury-neon" />
        </button>
      </div>

      <DailyFuelDial 
        currentCalories={totalFuel} 
        goalCalories={data.calorieGoal} 
        steps={data.steps} 
        isMet={isTargetMet} 
        isTracking={isTracking}
        onToggleTracking={onToggleTracking}
      />

      <StreakWidget 
        completedDates={displayDates} 
        onSeeMore={() => setShowHistory(true)} 
      />

      <div className="grid grid-cols-2 gap-4">
        <MetricCard 
          label="Active Energy" 
          value={Math.floor(data.calories)} 
          unit="KCAL" 
          icon={<Flame size={20} />} 
          progress={(data.calories / (data.calorieGoal || 1)) * 100} 
          color="#CEF245"
          delay={0.1} 
        />
        <MetricCard 
          label="Distance" 
          value={data.distance.toFixed(2)} 
          unit="KM" 
          icon={<Footprints size={20} />} 
          progress={(data.distance / (data.distanceGoal || 1)) * 100}
          color="#CEF245"
          delay={0.2} 
        />
      </div>

      <AnimatePresence>
        {isEditing && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex flex-col items-center justify-center p-8">
            <button onClick={() => setIsEditing(false)} className="absolute top-10 right-10 p-3 bg-white/5 rounded-full"><X size={28} className="text-white" /></button>
            <h2 className="text-2xl font-black mb-12 text-white uppercase tracking-[0.2em]">Calibration</h2>

            <div className="w-full max-w-sm space-y-8">
                <div className="space-y-4">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em]">Fuel Protocol (KCAL)</label>
                    <input 
                      type="number" 
                      value={localCalorieGoal} 
                      onChange={(e) => setLocalCalorieGoal(parseInt(e.target.value) || 0)}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl p-6 text-3xl font-black text-white focus:border-luxury-neon outline-none"
                    />
                </div>

                <div className="space-y-4">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em]">Step Protocol</label>
                    <input 
                      type="number" 
                      value={localStepGoal} 
                      onChange={(e) => setLocalStepGoal(parseInt(e.target.value) || 0)}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl p-6 text-3xl font-black text-white focus:border-luxury-neon outline-none"
                    />
                </div>

                <div className="space-y-4">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em]">Distance Protocol (KM)</label>
                    <input 
                      type="number"
                      step="0.1" 
                      value={localDistanceGoal} 
                      onChange={(e) => setLocalDistanceGoal(parseFloat(e.target.value) || 0)}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl p-6 text-3xl font-black text-white focus:border-luxury-neon outline-none"
                    />
                </div>

                <button 
                  onClick={handleApplyProtocols} 
                  disabled={isSaving} 
                  className="w-full py-6 bg-luxury-neon text-black font-black uppercase tracking-[0.2em] rounded-[2rem] shadow-[0_0_30px_rgba(206,242,69,0.3)] disabled:opacity-50"
                >
                  {isSaving ? <Loader2 className="animate-spin mx-auto" /> : "Commit Changes"}
                </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
      {showHistory && userId && <StreakHistory userId={userId} onClose={() => setShowHistory(false)} />}
    </div>
  );
};

export default Dashboard;

import React, { ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Using React.Component explicitly with generic parameters to ensure 'state', 'props', and 'setState' are correctly identified by the TypeScript compiler
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Fix: Correctly initialize state on the class instance
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: Accessing state inherited from React.Component
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                // Fix: setState is a built-in method of React.Component
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    // Fix: props.children is provided by the base React.Component class
    return this.props.children;
  }
}

// --- ORIENTATION LOCK IMPLEMENTATION ---
const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  // @ts-ignore
  if (isMobile && screen.orientation && typeof screen.orientation.lock === 'function') {
    try {
      // @ts-ignore
      await screen.orientation.lock('portrait');
    } catch (error) {
      console.debug("Orientation lock skipped:", error);
    }
  }
};

// Attempt lock on initialization without blocking
lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { User, Mail, Weight, Ruler, Calendar, Activity, LogOut, Edit3, Save, X, Camera, Upload, Loader2, AlertCircle, CheckCircle, Trash2 } from 'lucide-react';
import { UserProfile, UserMetrics } from '../types';
import { checkUserProfile, signOut, updateProfile, updateUserMetrics, supabase, DEFAULT_AVATAR } from '../services/supabase';

interface ProfileScreenProps {
  profile: UserProfile | null;
  metrics: UserMetrics;
  onUpdateMetrics: (metrics: UserMetrics) => void;
}

interface SnackBarState {
    show: boolean;
    message: string;
    type: 'success' | 'error';
}

const ProfileScreen: React.FC<ProfileScreenProps> = ({ profile, metrics, onUpdateMetrics }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [tempMetrics, setTempMetrics] = useState<UserMetrics>(metrics);
  const [tempName, setTempName] = useState(profile?.name || '');
  const [tempAvatar, setTempAvatar] = useState(profile?.avatarUrl || DEFAULT_AVATAR);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Custom Confirmation Modals
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  // SnackBar / Toast State
  const [snackBar, setSnackBar] = useState<SnackBarState>({ show: false, message: '', type: 'success' });

  // Sync state when props change
  useEffect(() => {
    if (profile?.name) setTempName(profile.name);
    setTempAvatar(profile?.avatarUrl || DEFAULT_AVATAR);
    setTempMetrics(metrics);
  }, [profile, metrics]);

  // Auto-hide SnackBar
  useEffect(() => {
      if (snackBar.show) {
          const timer = setTimeout(() => {
              setSnackBar(prev => ({ ...prev, show: false }));
          }, 4000);
          return () => clearTimeout(timer);
      }
  }, [snackBar.show]);

  const handleSave = async () => {
    setIsSaving(true);
    setSnackBar({ show: false, message: '', type: 'success' });

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("No active session found.");

      await updateProfile(user, { displayName: tempName, photoURL: tempAvatar });
      await updateUserMetrics(user.id, tempMetrics);
      await checkUserProfile(user.id);

      onUpdateMetrics(tempMetrics);
      setSnackBar({ show: true, message: "Profile synchronized successfully.", type: 'success' });
      setIsEditing(false);
    } catch (e: any) {
      setSnackBar({ show: true, message: "Update Failed: Check Database Permissions", type: 'error' });
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteAccount = async () => {
    setIsDeleting(true);
    try {
      const { error } = await supabase.rpc('delete_user_account');
      if (error) throw error;

      await signOut();
      // App.tsx handles redirect to login automatically via onAuthStateChanged
    } catch (e: any) {
      console.error("Account Deletion Failed:", e);
      setSnackBar({ 
          show: true, 
          message: "Deletion failed. Contact support.", 
          type: 'error' 
      });
      setIsDeleting(false);
      setShowDeleteConfirm(false);
    }
  };

  const handleAvatarClick = () => {
    if (isEditing && fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (ev.target?.result) {
          setTempAvatar(ev.target.result as string);
        }
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  const confirmLogout = async () => {
      await signOut();
      setShowLogoutConfirm(false);
  };

  if (!profile) {
    return (
      <div className="h-full w-full flex flex-col items-center justify-center p-8 text-center bg-black">
        <div className="w-24 h-24 rounded-full bg-white/5 flex items-center justify-center mb-6">
          <User size={48} className="text-gray-600" />
        </div>
        <h2 className="text-2xl font-black text-white uppercase tracking-widest mb-4">Profile Missing</h2>
        <p className="text-gray-500 text-sm mb-8 leading-relaxed">System identity records not found.</p>
        <button onClick={() => window.location.reload()} className="px-8 py-4 bg-luxury-neon text-black font-black uppercase tracking-widest text-xs rounded-2xl shadow-lg">
          Reload System
        </button>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex flex-col bg-black overflow-y-auto no-scrollbar pb-[calc(10rem+env(safe-area-inset-bottom))] relative">

      {/* --- LOGOUT CONFIRMATION MODAL --- */}
      <AnimatePresence>
        {showLogoutConfirm && (
           <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex flex-col items-center justify-center p-8"
           >
              <motion.div 
                 initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 20 }}
                 className="w-full max-w-sm glass-card p-8 rounded-3xl border border-white/10 text-center"
              >
                 <div className="w-16 h-16 rounded-full bg-red-500/20 flex items-center justify-center mx-auto mb-6 text-red-500">
                    <LogOut size={32} />
                 </div>
                 <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">Disconnect?</h3>
                 <p className="text-gray-400 text-xs mb-8">You will be logged out of Healthy.hub. Unsaved session data may be cleared.</p>

                 <div className="flex gap-4">
                    <button 
                       onClick={() => setShowLogoutConfirm(false)}
                       className="flex-1 py-4 bg-white/5 rounded-2xl text-white font-bold text-xs uppercase tracking-widest hover:bg-white/10"
                    >
                       Cancel
                    </button>
                    <button 
                       onClick={confirmLogout}
                       className="flex-1 py-4 bg-red-600 rounded-2xl text-white font-bold text-xs uppercase tracking-widest shadow-lg shadow-red-600/20 hover:bg-red-500"
                    >
                       Sign Out
                    </button>
                 </div>
              </motion.div>
           </motion.div>
        )}
      </AnimatePresence>

      {/* --- DELETE ACCOUNT CONFIRMATION MODAL --- */}
      <AnimatePresence>
        {showDeleteConfirm && (
           <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-md flex flex-col items-center justify-center p-8"
           >
              <motion.div 
                 initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 20 }}
                 className="w-full max-w-sm glass-card p-8 rounded-3xl border border-red-500/20 text-center"
              >
                 <div className="w-16 h-16 rounded-full bg-red-500/30 flex items-center justify-center mx-auto mb-6 text-red-500">
                    <Trash2 size={32} />
