               className="px-8 py-3 rounded-full bg-luxury-neon text-black text-xs font-black uppercase tracking-widest shadow-[0_0_20px_rgba(206,242,69,0.3)] hover:scale-105 transition-all flex items-center gap-2 disabled:opacity-50"
             >
               {isSaving ? <Loader2 size={14} className="animate-spin"/> : <Save size={14} />} Save Changes
             </button>
           </div>
        )}
      </div>

      <div className="px-6 flex-1 flex flex-col">
        <div className="glass-card p-6 rounded-[2.5rem] border border-white/5">
           <div className="mb-6 px-2">
              <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.4em]">Personal Data</h3>
           </div>

           <div className="grid grid-cols-2 gap-4">
             <MetricCard 
               icon={<Weight size={18} />} 
