               value={isEditing ? 
                 <input type="number" className="bg-white/5 rounded-lg py-1 w-full text-center focus:outline-none focus:bg-white/10 text-white" value={tempMetrics.weight} onChange={e => setTempMetrics({...tempMetrics, weight: parseFloat(e.target.value)})} /> : 
                 tempMetrics.weight
               } 
               unit="kg" 
               editable={isEditing}
             />
             <MetricCard 
               icon={<Ruler size={18} />} 
               label="Height" 
               value={isEditing ? 
                 <input type="number" className="bg-white/5 rounded-lg py-1 w-full text-center focus:outline-none focus:bg-white/10 text-white" value={tempMetrics.height} onChange={e => setTempMetrics({...tempMetrics, height: parseFloat(e.target.value)})} /> : 
                 tempMetrics.height
               } 
               unit="cm" 
               editable={isEditing}
             />
             <MetricCard 
               icon={<Calendar size={18} />} 
               label="Age" 
               value={isEditing ? 
                 <input type="number" className="bg-white/5 rounded-lg py-1 w-full text-center focus:outline-none focus:bg-white/10 text-white" value={tempMetrics.age || 25} onChange={e => setTempMetrics({...tempMetrics, age: parseInt(e.target.value)})} /> : 
                 tempMetrics.age || 25
               } 
