               editable={isEditing}
             />
             <MetricCard 
               icon={<Activity size={18} />} 
               label="Activity" 
               value={tempMetrics.activityLevel || 'moderate'} 
               unit="" 
               isActivity
             />
           </div>
        </div>

        {/* --- SETTINGS SECTION --- */}
        <div className="mt-8 space-y-2">
           <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.3em] px-4 mb-3">Settings & Security</p>

           <button 
             onClick={() => setShowLogoutConfirm(true)}
             className="w-full py-4 px-6 bg-white/5 border border-white/5 rounded-2xl flex items-center justify-between group hover:bg-white/10 transition-all"
           >
              <div className="flex items-center gap-3">
                 <LogOut size={16} className="text-gray-400 group-hover:text-white" />
                 <span className="text-xs font-black uppercase tracking-widest text-white/80 group-hover:text-white">Sign Out</span>
              </div>
              <X size={14} className="text-gray-700" />
           </button>

           <button 
             onClick={() => setShowDeleteConfirm(true)}
             className="w-full py-4 px-6 bg-red-500/5 border border-red-500/10 rounded-2xl flex items-center justify-between group hover:bg-red-500/10 transition-all mt-4"
           >
              <div className="flex items-center gap-3">
                 <Trash2 size={16} className="text-red-500/70 group-hover:text-red-500" />
                 <span className="text-xs font-black uppercase tracking-widest text-red-500/70 group-hover:text-red-500">Delete Account</span>
              </div>
              <AlertTriangle size={14} className="text-red-900" />
           </button>
        </div>
      </div>
    </div>
  );
};

const MetricCard: React.FC<{ icon: React.ReactNode, label: string, value: any, unit: string, isActivity?: boolean, editable?: boolean }> = ({ icon, label, value, unit, isActivity, editable }) => (
  <div className={`p-5 rounded-[2rem] flex flex-col items-center justify-center text-center transition-all ${editable ? 'bg-white/5 border border-white/10' : 'bg-transparent border border-white/5'}`}>
    <div className={`mb-2 ${editable ? 'text-luxury-neon' : 'text-gray-600'}`}>{icon}</div>
    <span className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-1">{label}</span>
    <div className="flex items-baseline gap-1 w-full justify-center">
      {typeof value === 'object' ? value : (
          <span className={`text-xl font-black text-white ${isActivity ? 'capitalize' : ''} ${editable ? 'w-full' : ''}`}>{value}</span>
      )}
      {!isActivity && unit && !editable && <span className="text-[9px] font-bold text-gray-600 uppercase">{unit}</span>}
      {editable && !isActivity && <span className="text-[9px] font-bold text-gray-500 uppercase ml-1">{unit}</span>}
    </div>
  </div>
);

export default ProfileScreen;

