import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, ArrowLeft, User, Ruler, Weight, Activity, Target, CheckCircle, Loader2, AlertCircle, LogOut } from 'lucide-react';
import { type User as SupabaseUser } from '@supabase/supabase-js';
import { Gender, ActivityLevel, FitnessGoal, UserProfile, ActivityData } from '../types';
import { completeOnboarding, DEFAULT_AVATAR, signOut } from '../services/supabase';

interface OnboardingScreenProps {
  user: SupabaseUser;
  onComplete: (profile: UserProfile) => void;
}

const OnboardingScreen: React.FC<OnboardingScreenProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLoggingOut, setIsLoggingOut] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState(user.user_metadata?.full_name || '');
  const [gender, setGender] = useState<Gender>('Male');
  const [dob, setDob] = useState('');

  // Changed defaults to string for easier manual input handling, parsed later
  const [heightStr, setHeightStr] = useState('175');
  const [weightStr, setWeightStr] = useState('75');

  const [activityLevel, setActivityLevel] = useState<ActivityLevel>('Moderately Active');
  const [goal, setGoal] = useState<FitnessGoal>('Maintain');

  const [errors, setErrors] = useState({ height: '', weight: '' });

  // Logic: Calculate Age
  const calculateAge = (dateString: string) => {
    const today = new Date();
    const birthDate = new Date(dateString);
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        age--;
    }
    return age;
  };

  const validateStep2 = () => {
    const h = parseFloat(heightStr);
    const w = parseFloat(weightStr);
    let valid = true;
    const newErrors = { height: '', weight: '' };

    if (isNaN(h) || h < 50 || h > 250) {
        newErrors.height = 'Valid range: 50 - 250 cm';
        valid = false;
    }
    if (isNaN(w) || w < 20 || w > 300) {
        newErrors.weight = 'Valid range: 20 - 300 kg';
        valid = false;
    }

    setErrors(newErrors);
    return valid;
  };

  const handleNextStep2 = () => {
      if (validateStep2()) {
          nextStep();
      }
  };

  const handleBackToLogin = async () => {
    setIsLoggingOut(true);
    try {
      await signOut();
      // Explicitly redirect to origin to simulate pushReplacement and clear onboarding state
      window.location.href = window.location.origin;
    } catch (e) {
      console.error("Logout failed", e);
      setIsLoggingOut(false);
    }
  };

  // The Magic: Calculate BMR & TDEE
  const handleSaveAndStart = async () => {
    setLoading(true);
    setSubmitError(null);

    try {
        // 1. Data Type Conversion (Crucial)
        const rawHeight = parseFloat(heightStr);
        const rawWeight = parseFloat(weightStr);
        const calculatedAge = dob ? calculateAge(dob) : 25;

        // Fallback safety
        const height = isNaN(rawHeight) ? 0.0 : rawHeight;
        const weight = isNaN(rawWeight) ? 0.0 : rawWeight;
        const age = isNaN(calculatedAge) ? 25 : calculatedAge;

        if (height <= 0 || weight <= 0) {
             throw new Error("Invalid height or weight detected.");
        }

        // 1. Mifflin-St Jeor Equation
        let bmr = (10 * weight) + (6.25 * height) - (5 * age);
        bmr += (gender === 'Male' ? 5 : -161);

        // 2. Activity Multiplier
        const multipliers: Record<ActivityLevel, number> = {
            'Sedentary': 1.2,
            'Lightly Active': 1.375,
            'Moderately Active': 1.55,
            'Very Active': 1.725
        };
        const tdee = bmr * multipliers[activityLevel];

        // 3. Goal Adjustment
        let calorieTarget = tdee;
        if (goal === 'Weight Loss') calorieTarget -= 500;
        if (goal === 'Muscle Gain') calorieTarget += 300;

        // 4. Construct Profile Data
        const metrics = {
            height,
            weight,
            age,
            gender,
            dob,
            activityLevel,
            fitnessGoal: goal,
            lastWeightUpdate: Date.now(),
            lastHeightUpdate: Date.now()
        };

        const profileData: UserProfile = {
            name: name || 'Elite Member',
            email: user.email || '',
            avatarUrl: user.user_metadata?.avatar_url || DEFAULT_AVATAR,
            metrics
        };

        // 5. Construct Goals
        let stepGoal = 8000;
        if (goal === 'Weight Loss') stepGoal += 2000;
        if (activityLevel === 'Very Active') stepGoal += 3000;
        if (activityLevel === 'Sedentary') stepGoal = 6000;

        const activityGoals: ActivityData = {
            steps: 0, calories: 0, distance: 0, history: [],
            stepGoal: stepGoal,
            calorieGoal: Math.round(calorieTarget),
            distanceGoal: parseFloat((stepGoal * 0.000762).toFixed(1)) // Approx 76cm stride
        };

        const savedProfile = await completeOnboarding(user, profileData, activityGoals);
        onComplete(savedProfile);

    } catch (e: any) {
        console.error("ERROR SAVING PROFILE:", e);
        setSubmitError(`Error saving profile: ${e.message || "Unknown Error"}`);
        setLoading(false);
    }
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  return (
    <div className="h-screen w-full bg-black flex flex-col items-center p-6 relative overflow-hidden">
       {/* Background Ambience */}
       <div className="absolute top-[-20%] right-[-20%] w-[80vw] h-[80vw] bg-luxury-neon/5 rounded-full blur-[100px] animate-pulse-slow"></div>
       <div className="absolute bottom-[-20%] left-[-20%] w-[80vw] h-[80vw] bg-luxury-gold/5 rounded-full blur-[100px] animate-pulse-slow"></div>

       {/* 1. TOP NAVIGATION ROW (Back to Login) */}
       <div className="w-full max-w-md z-20 flex items-center justify-start pt-4 pb-2">
          <button 
            onClick={handleBackToLogin}
            disabled={isLoggingOut || loading}
            className="flex items-center gap-2 group px-4 py-2 rounded-full hover:bg-white/5 transition-all disabled:opacity-50"
          >
            <div className="p-2 bg-luxury-neon/10 rounded-full group-hover:bg-luxury-neon/20 transition-all">
              {isLoggingOut ? (
                <Loader2 size={18} className="text-luxury-neon animate-spin" />
              ) : (
                <ArrowLeft size={18} className="text-luxury-neon" />
              )}
            </div>
            <span className="text-[11px] font-black text-gray-500 group-hover:text-gray-300 uppercase tracking-[0.2em] transition-all">
              {isLoggingOut ? 'Disconnecting...' : 'Back to Login'}
            </span>
          </button>
       </div>

       <div className="w-full max-w-md z-10 flex-1 flex flex-col justify-center">
          <div className="text-center mb-8">
             <h1 className="text-3xl font-black text-white uppercase tracking-tighter">System <span className="text-luxury-neon">Setup</span></h1>
             <p className="text-gray-500 text-xs font-bold uppercase tracking-[0.3em] mt-2">Step {step} of 3</p>
          </div>

          <div className="glass-panel rounded-[2.5rem] p-1 border border-white/10 shadow-2xl relative overflow-hidden">
             <AnimatePresence mode="wait">

                {/* STEP 1: BASICS */}
                {step === 1 && (
                    <motion.div key="step1" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-6">
                        <div className="flex items-center gap-3 mb-4 text-luxury-neon">
                            <User size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Identity</h2>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Display Name</label>
                                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" placeholder="Enter Name" />
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Biological Sex (For BMR)</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['Male', 'Female', 'Other'].map(g => (
                                        <button key={g} onClick={() => setGender(g as Gender)} className={`py-3 rounded-xl border text-xs font-bold transition-all ${gender === g ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-400 border-white/10'}`}>
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Date of Birth</label>
                                <input type="date" value={dob} onChange={e => setDob(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" />
                            </div>
                        </div>

                        <div className="pt-4 flex justify-end">
                            <button onClick={nextStep} disabled={!dob || !name} className="px-8 py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2 disabled:opacity-50">
                                Next <ChevronRight size={16} />
                            </button>
                        </div>
                    </motion.div>
                )}

                {/* STEP 2: BODY STATS */}
                {step === 2 && (
                    <motion.div key="step2" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-8">
                        <div className="flex items-center gap-3 mb-4 text-luxury-neon">
                            <Activity size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Metrics</h2>
                        </div>

                        <div className="space-y-8">

                            {/* Height Input */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">
                                    <Ruler size={14} className="text-luxury-neon" /> Height
                                </label>
                                <div className={`relative flex items-center bg-white/5 border rounded-3xl h-24 overflow-hidden transition-all duration-300 focus-within:shadow-[0_0_20px_rgba(206,242,69,0.15)] ${errors.height ? 'border-red-500 focus-within:border-red-500' : 'border-white/10 focus-within:border-luxury-neon'}`}>
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        value={heightStr}
                                        onChange={(e) => {
                                            setHeightStr(e.target.value);
                                            setErrors(prev => ({ ...prev, height: '' }));
                                        }}
                                        className="w-full h-full bg-transparent text-center text-4xl font-black text-white outline-none placeholder-gray-700 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none z-10 relative pl-4"
                                        placeholder="0"
                                    />
                                    <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                                        <span className="text-xs font-black text-gray-500 uppercase tracking-widest">CM</span>
                                    </div>
                                </div>
                                {errors.height && (
                                    <div className="flex items-center gap-2 text-red-400 text-xs font-bold animate-pulse px-2">
                                        <AlertCircle size={12} /> {errors.height}
                                    </div>
                                )}
                            </div>

                            {/* Weight Input */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">
                                    <Weight size={14} className="text-luxury-gold" /> Weight
                                </label>
                                <div className={`relative flex items-center bg-white/5 border rounded-3xl h-24 overflow-hidden transition-all duration-300 focus-within:shadow-[0_0_20px_rgba(245,158,11,0.15)] ${errors.weight ? 'border-red-500 focus-within:border-red-500' : 'border-white/10 focus-within:border-luxury-gold'}`}>
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        value={weightStr}
                                        onChange={(e) => {
                                            setWeightStr(e.target.value);
                                            setErrors(prev => ({ ...prev, weight: '' }));
                                        }}
                                        className="w-full h-full bg-transparent text-center text-4xl font-black text-white outline-none placeholder-gray-700 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none z-10 relative pl-4"
                                        placeholder="0"
                                    />
                                    <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                                        <span className="text-xs font-black text-gray-500 uppercase tracking-widest">KG</span>
                                    </div>
                                </div>
                                {errors.weight && (
                                    <div className="flex items-center gap-2 text-red-400 text-xs font-bold animate-pulse px-2">
                                        <AlertCircle size={12} /> {errors.weight}
                                    </div>
                                )}
                            </div>

                        </div>

                        <div className="pt-4 flex justify-between">
                             <button onClick={prevStep} className="px-6 py-4 bg-white/5 text-white font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                <ArrowLeft size={16} /> Back
                            </button>
                            <button onClick={handleNextStep2} className="px-8 py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                Next <ChevronRight size={16} />
                            </button>
                        </div>
                    </motion.div>
                )}

                {/* STEP 3: GOALS */}
                {step === 3 && (
                    <motion.div key="step3" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-6">
                        <div className="flex items-center gap-3 mb-2 text-luxury-neon">
                            <Target size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Mission</h2>
                        </div>

                        <div className="space-y-6 overflow-y-auto max-h-[50vh] no-scrollbar">
                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-3">Activity Level</label>
                                <div className="space-y-2">
                                    {['Sedentary', 'Lightly Active', 'Moderately Active', 'Very Active'].map(lvl => (
                                        <button key={lvl} onClick={() => setActivityLevel(lvl as ActivityLevel)} className={`w-full p-4 rounded-xl border text-left flex justify-between items-center transition-all ${activityLevel === lvl ? 'bg-luxury-neon/20 border-luxury-neon text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>
                                            <span className="text-xs font-bold uppercase">{lvl}</span>
                                            {activityLevel === lvl && <CheckCircle size={16} className="text-luxury-neon"/>}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-3">Primary Goal</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['Weight Loss', 'Maintain', 'Muscle Gain'].map(g => (
                                        <button key={g} onClick={() => setGoal(g as FitnessGoal)} className={`p-3 rounded-xl border text-[10px] font-bold uppercase transition-all ${goal === g ? 'bg-white text-black border-white' : 'bg-white/5 text-gray-400 border-white/10'}`}>
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {submitError && (
                            <motion.div 
                                initial={{ opacity: 0, y: -10 }} 
                                animate={{ opacity: 1, y: 0 }}
                                className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 mt-4"
                            >
                                <AlertCircle className="text-red-500 shrink-0 mt-0.5" size={16} />
                                <p className="text-red-400 text-xs font-bold leading-relaxed">{submitError}</p>
                            </motion.div>
                        )}

                        <div className="pt-2 flex justify-between">
                             <button onClick={prevStep} disabled={loading} className="px-6 py-4 bg-white/5 text-white font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                <ArrowLeft size={16} /> Back
                            </button>
                            <button onClick={handleSaveAndStart} disabled={loading} className="px-8 py-4 bg-luxury-neon text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2 shadow-[0_0_20px_rgba(206,242,69,0.4)]">
                                {loading ? <Loader2 className="animate-spin" size={16}/> : <>Save & Start <ChevronRight size={16} /></>}
                            </button>
                        </div>
                    </motion.div>
                )}
             </AnimatePresence>
          </div>
       </div>
    </div>
  );
};

export default OnboardingScreen;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Explicitly use React.Component with generics to resolve property access errors for state, props, and setState
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Fix: Explicitly initialize state on the class instance, inherited from React.Component
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: Correctly access state inherited from React.Component
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                // Fix: setState is correctly inherited and accessible from React.Component
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    // Fix: Correctly access props inherited from React.Component
    return this.props.children;
  }
}

