import React, { useState, useEffect, useRef } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  checkUserProfile, 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity,
  getLocalTodayKey
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserProfile, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  const [isDataLoaded, setIsDataLoaded] = useState(false);
  const loadedDateKeyRef = useRef<string | null>(null);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps, status, error: pedometerError } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      if (user) {
        setCurrentUser(user);
        setIsDataLoaded(false); 
        setIsProfileChecking(true);

        const todayKey = getLocalTodayKey();
        loadedDateKeyRef.current = todayKey;

        const dashboardData = await fetchFullUserDashboard(user.id);

        if (dashboardData && dashboardData.profile) {
            const { profile, todayActivity } = dashboardData;
            setUserProfile(profile);

            setActivityData(prev => ({
              ...prev,
              steps: todayActivity?.steps || 0,
              calories: todayActivity?.calories_burned || 0,
              stepGoal: profile.goals?.stepGoal || prev.stepGoal,
              calorieGoal: profile.goals?.calorieGoal || prev.calorieGoal
            }));
        }

        setIsDataLoaded(true);
        setIsProfileChecking(false);
      } else { 
        setCurrentUser(null); 
        setUserProfile(null); 
        setIsDataLoaded(false);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    if (!isDataLoaded || !currentUser) return;

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);
          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, isDataLoaded, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-xs uppercase tracking-widest">Initialising...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-xs uppercase tracking-widest">Loading...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden">
      <main className="flex-1 relative w-full overflow-hidden">
        {currentView === ViewState.DASHBOARD && <Dashboard data={activityData} onUpdateGoals={handleUpdateGoals} isTracking={isTracking} onToggleTracking={toggleTracking} foodHistory={foodHistory} />}
        {currentView === ViewState.CHAT && <ChatBot metrics={bmiMetrics} activity={activityData} />}
        {currentView === ViewState.FOOD_LENS && <FoodLens history={foodHistory} onAddToHistory={h => setFoodHistory([h, ...foodHistory])} />}
        {currentView === ViewState.BMI_HUB && <BMIHub />}
        {currentView === ViewState.PROFILE && <ProfileScreen onUpdateMetrics={setBmiMetrics} />}
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Use the named Component import to ensure that TypeScript correctly identifies the base class and its properties (state, props, setState).
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Fix: Correctly initialize state on the class instance, inherited from Component.
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: State is correctly inherited and accessible from Component.
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                // Fix: setState is correctly inherited and accessible from Component.
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    // Fix: Props are correctly inherited and accessible from Component.
    return this.props.children;
  }
}

