// --- DATE HELPER ---
export const getLocalTodayKey = (): string => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const isGuest = (userId: string) => userId.startsWith('guest_');

// --- SYNC FUNCTION (WITH DEBUGGING) ---
export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) return;

  // Print Log 1: Starting Sync
  console.log(`🔄 Starting Sync for User: ${userId}`);

  const todayKey = getLocalTodayKey();
  const isTargetMet = steps >= stepGoal;

  try {
    // Upsert Logic: STRICTLY 'daily_activity'
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });

    if (error) throw error;

    // Print Log 2: Success
    console.log(`✅ Saved! Steps: ${steps}`);

  } catch (e) {
    // Print Log 3: Error
    console.error(`❌ ERROR SAVING:`, e);
  }
};

// --- FETCH FUNCTION (WITH DEBUGGING) ---
export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) return null;

  try {
    const todayKey = getLocalTodayKey();

    // Fetch User Profile
    const { data: profileData } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (!profileData) return null;

    // Fetch Today Activity: STRICTLY 'daily_activity'
    const { data, error } = await supabase
      .from('daily_activity')
      .select('*')
      .eq('user_id', userId)
      .eq('activity_date', todayKey)
      .maybeSingle();

    if (error) throw error;

    // DEBUG PRINT (CRITICAL)
    console.log(`🔍 RAW DATABASE RESPONSE:`, data);

    if (!data) {
      console.log('⚠️ No data found for today. Starting at 0.');
    } else {
      console.log(`✅ RESTORED STEPS: ${data.steps}`);
    }

    // Fetch supplementary data
    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: data,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    console.error("Fetch Logic Error:", e);
    return null;
  }
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: dbProfile.metrics || {}
  };
};

