import React, { ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Use React.Component directly to resolve TypeScript errors where 'state', 'props', and 'setState' were not found on the ErrorBoundary class.
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Fix: Correctly initialize state on the class instance inherited from React.Component.
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: Access state through React.Component inheritance which ensures TypeScript correctly identifies the base class properties.
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                // Fix: Call setState inherited from React.Component.
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    // Fix: Access props through React.Component inheritance.
    return this.props.children;
  }
}

// --- ORIENTATION LOCK IMPLEMENTATION ---
const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  // @ts-ignore
  if (isMobile && screen.orientation && typeof screen.orientation.lock === 'function') {
    try {
      // @ts-ignore
      await screen.orientation.lock('portrait');
    } catch (error) {
      console.debug("Orientation lock skipped:", error);
    }
  }
};

// Attempt lock on initialization without blocking
lockOrientation().catch(() => {});

