const GUEST_KEY = 'healthy_hub_guest_session';

export const isGuest = (userId: string | undefined): boolean => {
  if (!userId) return false;
  return userId.startsWith('guest_') || localStorage.getItem(GUEST_KEY) === 'true';
};

export const getGuestUser = (): User => ({
  id: 'guest_elite_member',
  email: 'guest@healthyhub.com',
  app_metadata: {},
  user_metadata: { full_name: 'Guest Elite' },
  aud: 'authenticated',
  created_at: new Date().toISOString()
});

// --- SYNC FUNCTION (WITH DEBUGGING) ---
export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) {
    console.log("Guest mode active: Skipping cloud sync.");
    return;
  }

  console.log(`🔄 Starting Sync for User: ${userId}`);
  const todayKey = getLocalTodayKey();
  const isTargetMet = steps >= stepGoal;

  try {
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });

    if (error) throw error;
    console.log(`✅ Saved! Steps: ${steps}`);
  } catch (e) {
    console.error(`❌ ERROR SAVING:`, e);
  }
};

// --- FETCH FUNCTION (WITH DEBUGGING) ---
export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    return {
      profile: {
        id: userId,
        name: 'Guest Elite',
        email: 'guest@healthyhub.com',
        avatarUrl: DEFAULT_AVATAR,
        goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0 },
        metrics: {}
      },
      todayActivity: null,
      foodLogs: [],
      chatHistory: []
    };
  }

  try {
    const todayKey = getLocalTodayKey();
    const { data: profileData } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (!profileData) return null;

    const { data, error } = await supabase
      .from('daily_activity')
      .select('*')
      .eq('user_id', userId)
      .eq('activity_date', todayKey)
      .maybeSingle();

    if (error) throw error;

    console.log(`🔍 RAW DATABASE RESPONSE:`, data);

    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: data,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    console.error("Fetch Logic Error:", e);
    return null;
  }
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: dbProfile.metrics || {}
  };
};

export const checkUserProfile = async (uid: string) => {
    if (isGuest(uid)) return null;
    const { data } = await supabase.from('profiles').select('*').eq('id', uid).maybeSingle();
    return data ? mapProfileToAppFormat(data) : null;
};

export const onAuthStateChanged = (callback: (user: User | null) => void) => {
  // First, check if there's a local guest session
  const guestActive = localStorage.getItem(GUEST_KEY) === 'true';
  if (guestActive) {
    callback(getGuestUser());
  }

  return supabase.auth.onAuthStateChange((_event, session) => {
    if (session?.user) {
      localStorage.removeItem(GUEST_KEY); // Real user clears guest flag
      callback(session.user);
    } else if (!guestActive) {
      callback(null);
    }
  }).data.subscription.unsubscribe;
};

export const signInWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signInWithPassword({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem(GUEST_KEY);
  return data;
};

export const signOut = async () => {
  localStorage.removeItem(GUEST_KEY);
  await supabase.auth.signOut();
};

export const createUserWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signUp({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem(GUEST_KEY);
  return { data };
};

export const createUserDocument = async (user: User, name: string) => {
  if (isGuest(user.id)) return;
  await supabase.from('profiles').upsert({ id: user.id, email: user.email, name, avatar_url: DEFAULT_AVATAR });
