interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Use explicitly imported 'Component' from 'react' to resolve TypeScript errors where 'state', 'props', and 'setState' were not found on the ErrorBoundary class.
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Fix: Correctly initialize state on the class instance, now correctly recognized through Component inheritance.
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: Access state through correctly typed inheritance from Component.
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
