                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Display Name</label>
                                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" placeholder="Enter Name" />
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Biological Sex (For BMR)</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['Male', 'Female', 'Other'].map(g => (
                                        <button key={g} onClick={() => setGender(g as Gender)} className={`py-3 rounded-xl border text-xs font-bold transition-all ${gender === g ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-400 border-white/10'}`}>
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Date of Birth</label>
                                <input type="date" value={dob} onChange={e => setDob(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" />
                            </div>
                        </div>

                        <div className="pt-4 flex justify-end">
                            <button onClick={nextStep} disabled={!dob || !name} className="px-8 py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2 disabled:opacity-50">
                                Next <ChevronRight size={16} />
                            </button>
                        </div>
                    </motion.div>
                )}

                {/* STEP 2: BODY STATS */}
                {step === 2 && (
                    <motion.div key="step2" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-8">
                        <div className="flex items-center gap-3 mb-4 text-luxury-neon">
                            <Activity size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Metrics</h2>
                        </div>

                        <div className="space-y-8">

                            {/* Height Input */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">
                                    <Ruler size={14} className="text-luxury-neon" /> Height
                                </label>
                                <div className={`relative flex items-center bg-white/5 border rounded-3xl h-24 overflow-hidden transition-all duration-300 focus-within:shadow-[0_0_20px_rgba(206,242,69,0.15)] ${errors.height ? 'border-red-500 focus-within:border-red-500' : 'border-white/10 focus-within:border-luxury-neon'}`}>
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        value={heightStr}
                                        onChange={(e) => {
                                            setHeightStr(e.target.value);
                                            setErrors(prev => ({ ...prev, height: '' }));
                                        }}
                                        className="w-full h-full bg-transparent text-center text-4xl font-black text-white outline-none placeholder-gray-700 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none z-10 relative pl-4"
                                        placeholder="0"
                                    />
                                    <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                                        <span className="text-xs font-black text-gray-500 uppercase tracking-widest">CM</span>
                                    </div>
                                </div>
                                {errors.height && (
                                    <div className="flex items-center gap-2 text-red-400 text-xs font-bold animate-pulse px-2">
                                        <AlertCircle size={12} /> {errors.height}
                                    </div>
                                )}
                            </div>

                            {/* Weight Input */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">
                                    <Weight size={14} className="text-luxury-gold" /> Weight
                                </label>
                                <div className={`relative flex items-center bg-white/5 border rounded-3xl h-24 overflow-hidden transition-all duration-300 focus-within:shadow-[0_0_20px_rgba(245,158,11,0.15)] ${errors.weight ? 'border-red-500 focus-within:border-red-500' : 'border-white/10 focus-within:border-luxury-gold'}`}>
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        value={weightStr}
                                        onChange={(e) => {
                                            setWeightStr(e.target.value);
                                            setErrors(prev => ({ ...prev, weight: '' }));
                                        }}
                                        className="w-full h-full bg-transparent text-center text-4xl font-black text-white outline-none placeholder-gray-700 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none z-10 relative pl-4"
                                        placeholder="0"
                                    />
                                    <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                                        <span className="text-xs font-black text-gray-500 uppercase tracking-widest">KG</span>
                                    </div>
                                </div>
                                {errors.weight && (
                                    <div className="flex items-center gap-2 text-red-400 text-xs font-bold animate-pulse px-2">
                                        <AlertCircle size={12} /> {errors.weight}
                                    </div>
                                )}
                            </div>

                        </div>

                        <div className="pt-4 flex justify-between">
                             <button onClick={prevStep} className="px-6 py-4 bg-white/5 text-white font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                <ArrowLeft size={16} /> Back
                            </button>
                            <button onClick={handleNextStep2} className="px-8 py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                Next <ChevronRight size={16} />
                            </button>
                        </div>
                    </motion.div>
                )}

                {/* STEP 3: GOALS */}
                {step === 3 && (
                    <motion.div key="step3" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-6">
                        <div className="flex items-center gap-3 mb-2 text-luxury-neon">
                            <Target size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Mission</h2>
                        </div>

                        <div className="space-y-6 overflow-y-auto max-h-[50vh] no-scrollbar">
                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-3">Activity Level</label>
                                <div className="space-y-2">
                                    {['Sedentary', 'Lightly Active', 'Moderately Active', 'Very Active'].map(lvl => (
                                        <button key={lvl} onClick={() => setActivityLevel(lvl as ActivityLevel)} className={`w-full p-4 rounded-xl border text-left flex justify-between items-center transition-all ${activityLevel === lvl ? 'bg-luxury-neon/20 border-luxury-neon text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>
                                            <span className="text-xs font-bold uppercase">{lvl}</span>
                                            {activityLevel === lvl && <CheckCircle size={16} className="text-luxury-neon"/>}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-3">Primary Goal</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['Weight Loss', 'Maintain', 'Muscle Gain'].map(g => (
                                        <button key={g} onClick={() => setGoal(g as FitnessGoal)} className={`p-3 rounded-xl border text-[10px] font-bold uppercase transition-all ${goal === g ? 'bg-white text-black border-white' : 'bg-white/5 text-gray-400 border-white/10'}`}>
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {submitError && (
                            <motion.div 
                                initial={{ opacity: 0, y: -10 }} 
                                animate={{ opacity: 1, y: 0 }}
                                className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 mt-4"
                            >
                                <AlertCircle className="text-red-500 shrink-0 mt-0.5" size={16} />
                                <p className="text-red-400 text-xs font-bold leading-relaxed">{submitError}</p>
                            </motion.div>
                        )}

                        <div className="pt-2 flex justify-between">
                             <button onClick={prevStep} disabled={loading} className="px-6 py-4 bg-white/5 text-white font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2">
                                <ArrowLeft size={16} /> Back
                            </button>
                            <button onClick={handleSaveAndStart} disabled={loading} className="px-8 py-4 bg-luxury-neon text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2 shadow-[0_0_20px_rgba(206,242,69,0.4)]">
                                {loading ? <Loader2 className="animate-spin" size={16}/> : <>Save & Start <ChevronRight size={16} /></>}
                            </button>
                        </div>
                    </motion.div>
                )}
             </AnimatePresence>
          </div>
       </div>
    </div>
  );
};

export default OnboardingScreen;

import React, { ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
// Fix: Changed inheritance to explicitly use React.Component to resolve property 'state', 'props', and 'setState' not found errors in TypeScript.
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // Fix: Explicitly declare the state property on the class to satisfy TypeScript's property checks.
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  constructor(props: ErrorBoundaryProps) {
    super(props);
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    // Fix: Access state through correctly typed inheritance from React.Component.
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                // Fix: Call setState inherited from the base React.Component class.
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    // Fix: Access props correctly through React.Component inheritance.
    return this.props.children;
  }
}

// --- ORIENTATION LOCK IMPLEMENTATION ---
const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  // @ts-ignore
  if (isMobile && screen.orientation && typeof screen.orientation.lock === 'function') {
    try {
      // @ts-ignore
      await screen.orientation.lock('portrait');
    } catch (error) {
      console.debug("Orientation lock skipped:", error);
    }
  }
};

// Attempt lock on initialization without blocking
lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}
